import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"众我","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/众我.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/众我.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/4.B级/众我.md"};function o(d,b,l,i,_,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"众我",tabindex:"-1"},[t("众我 "),r("a",{class:"header-anchor",href:"#众我","aria-label":'Permalink to "众我"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="众我-1" tabindex="-1">众我 <a class="header-anchor" href="#众我-1" aria-label="Permalink to &quot;众我&quot;">​</a></h1><p>众我<br> 魔幻本质<br> B+2000<br> 高塔之内，充斥着昔日与未来的失败者或迷失者。他们被岁月模糊了意识，忘却了自己身为何人，但意识弥留之际的愿望却得到了最好的保留——离开这座高塔。然深陷时间漩涡的他们已经失去了自己的锚点，注定作为游魂被束缚在塔内终生。</p><p>除非，有人愿意与他们分享自己的可能性。</p><p>“吾非汝，子非我”<br> “我们只是被困在乱流之中的可怜人”<br> “.....唉，连自己都忘了是谁...”</p><p>“若汝应允，还请携上吾等”<br> “困在这里的日子真的很无聊啊”<br> “...拜托了！”</p><p>介绍：<br> 当你同意分享自己的可能性后，这些被困塔内的游魂将化作你千千万万的可能性之一。然而他们终究不是你，你也不该成为他们。故而他们只能向你展现其他可能的你应该是何模样，应该如何为人，又有何成就。但还请牢记——他们只是窗口，无法带来真正的你。</p><p>▓▓▓▓人物描述（由购买者自行决定，通常与购买的轮回者相同）<br> 姓名:<br> 性别：<br> 年龄：<br> 身高/体重:<br> 种族/国籍:<br> 语言：<br> 相貌:5+15（传奇风度）<br> 性格/特征：<br> 概述：<br> 角色概念:</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量 14<br> ■敏捷 11<br> ■耐力 16<br> ▓▓心智属性<br> ■智力 14<br> ■感知 14<br> ■决心 11<br> ▓▓互动属性<br> ■风度 16<br> ■操控 14<br> ■沉着 11</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动 8<br> 专业：反射8<br> ■求生 8<br> 专业：强韧8<br> ■射击 1<br> ■武技 1</p><p>▓▓心智系<br> ■学识 8<br> 专业:解读8<br> ■器用 11<br> 专业：操控电脑11<br> ■手艺 1<br> ■专注 8<br> 专业：意志8</p><p>▓▓互动系<br> ■洞察 11<br> 专业：搜索8侦查11<br> ■隐秘 1<br> ■表达 1<br> ■社交 1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 36（力量【14】+敏捷【11】+体积【5】+每1点敏捷上的附加获得3移动速度+其他加值）<br> ▓先攻 22+3D10（敏捷【11】+沉着【11】+沉着附加2D10+其他加值1D10+）<br> ▓基础防御 12+2（敏捷感知的平均值【12】+较高者的附加成功【2】）<br> ▓生命值 36（耐力【16】+体积【5】+耐力附加【3】×5）<br> ▓意志力池 26（决心【11】+沉着【11】+决心附加【2】×2+其他加值）<br> ▓意志豁免 32+5（决心【11】+专注8+意志【8】+传奇决心【2】）<br> ▓反射豁免 30+5（敏捷【11】+运动8+反射【8】）<br> ▓强韧豁免 35+6（耐力【16】+生存8+强韧【8】）<br> ▓侦查 41+6（感知【14】+洞察11+侦查【11】）<br> ▓敏感范围 320米（感知【14】*20米+感知上的附加成功【2】*20米）</p><p>▓▓▓▓攻击预设：<br> 肉搏攻击20+4<br> 其他效果：</p><p>▓▓▓▓防御预设：<br> 常态12+2<br> 其他效果</p><p>▓▓▓▓专长：<br> 众魂铸就之我（3）<br> “重获自由...重而为人”<br> “久违的阳光，舒坦的气息”<br> “...可算出来了！真希望不用回去...”</p><p>众我即为你心灵的延伸，你们的内在因可能性的锚定而纠缠在一起——你是他们的一员，而他们并非单独的你。身为魂魄的他们尽管被束缚在肉身中丧失了诸多便利，但建立起即刻联系的心灵感知仍有余力。这视为一个B级时空来源的心灵通讯能力，并且众我与拥有者始终会保持着心灵通讯，只要不被其他因素阻止；拥有者也可以通过众我与主动接受并愿意开放心灵的其他人建立联系，只要众我还存在，就可以共享该心灵通讯能力。</p><p>众因塑造之我（3）<br> “有因必有果...无心之举亦可创下巨变”<br> “汝要牢记，切莫让眼前的表象迷惑了此行真正的意图”<br> “...吾会向你展示，千万之中的你为何模样”</p><p>众我在进入影片时，会获得一个B级时空来源的背景身份，通常为当前世界观的原住民，具有对应的在当地居住超过一年的生活记录、租房记录、出入证明与身份证明，并视情况拥有一个中等偏下的普通薪资工作（刚好养活自己）。虽然这并非与你本人绑定，但两者相近的外貌或许总能给你带来一些便利，但你不该是众我的一员，故而难免会被识破。</p><p>ST选开：众我进入影片后有可能因为身份问题导致并不在拥有者身旁</p><p>众人所见之我（3）<br> “或许你经历已多，不是我这号人可以教导你的”<br> “但我还是希望你不会成为我们的一员”<br> “不必太过在意别人的目光，你有更重要的人值得关注，不是吗？”<br> “我会在你需要的时候出现的”</p><p>一念之间，从阴影中走出的可能并非原先的少年，而是磨砺已久的帝皇。<br> 众我可以花费十分钟至一小时的准备时间，在一处已知地点与自身的阴影之间打开一道单向传送阵，随后可钻入身下的阴影去往另一侧的传送阵所在，通常也是位于一处阴影中，传送阵两端的距离极限不能超过8000km。<br> 传送阵持续至多一轮，期间进入的单位会传送至另一侧，这是一个B级的传送类旅行能力。</p><p>众世排斥之我（3）<br> “...不被接纳的感觉很不好啊...但不被接纳未必是坏事”<br> “是吧，连世界都不接纳你，那不就没有人束缚你了吗？”</p><p>众我获得等同于基础移动速度的，在阴影覆盖的固体物质间穿行的速度，这一遁地行为具有3点遁力。</p><p>自寻短见（1）<br> “毋须担心...”<br> “明日我们还会相见”</p><p>“...呜，你要注意安全啊！”</p><p>众我拥有自由行动的能力，自然也有掌握其自我生死的能力。在非战斗场景下可花费1分钟左右缓慢崩解自身，随即死亡。如果没有受到其他效果影响，则正常按照随从规则复活。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',28)])])}const m=p(s,[["render",o]]);export{f as __pageData,m as default};
